def generate_plant_graph(sequence):
    node_dict = {
        'A': [},  # A-1 node, B-2 node, ..., AB-n
          'B': [],  # B-3 node, A-4 node, ..., B-n
          'C': [],  # C-1 node, A-2 node, ... BC-n
          },
        'D': []
    }

    for i in range(len(sequence) - 1):
        node = node_dict.get('A', None)
        if node is not None:
            node['C'].append(node)
        else:
            node['D'].append(None)

    # Generate the final graph
    for i in range(len(sequence)):
        node_dict[i]['C'] += sequence[i]
        node_dict[i]['D'].extend([None]*len(sequence))

    return node_dict
